    try std.testing.expectEqual(@as(u32, 3), view.request_id);
    try std.testing.expectEqual(@as(u64, 99), view.owner_client_id);
    try std.testing.expectEqual(startup_probe.ProbeKind.osc_11, view.probe_kind);
}

